// Configure your repos here
const repos = [
  'emilvrana/n8n-workflows',
  'emilvrana/local-rag-stack',
  'emilvrana/deepl-cli'
];

// Look back this many hours (match schedule interval)
const lookbackHours = 24;
const since = new Date(Date.now() - lookbackHours * 3600 * 1000).toISOString();

return repos.map(repo => ({
  json: { repo, since }
}));

// Merge commits and issues into a single summary object per repo
const allItems = $input.all();

// Group by repo (we get interleaved results from both HTTP nodes)
// Build a plain text summary for the LLM
const commitItems = allItems.filter(i => Array.isArray(i.json) && i.json[0]?.commit);
const issueItems  = allItems.filter(i => Array.isArray(i.json) && i.json[0]?.html_url?.includes('/issues/'));

let summary = '';

for (const item of commitItems) {
  if (!item.json.length) continue;
  const repo = item.json[0].html_url.split('/commit/')[0].replace('https://github.com/', '');
  const commits = item.json.map(c =>
    `- ${c.commit.message.split('\n')[0]} (${c.author?.login ?? 'unknown'})`
  ).join('\n');
  summary += `**${repo}** — ${item.json.length} commit(s):\n${commits}\n\n`;
}

for (const item of issueItems) {
  if (!item.json.length) continue;
  const repo = item.json[0].repository_url.replace('https://api.github.com/repos/', '');
  const issues = item.json.map(i => `- #${i.number} ${i.title} [${i.state}]`).join('\n');
  summary += `**${repo}** — ${item.json.length} issue(s) updated:\n${issues}\n\n`;
}

if (!summary.trim()) {
  return [{ json: { skip: true, message: 'No GitHub activity in the last 24h.' } }];
}

return [{ json: { skip: false, rawSummary: summary.trim() } }];

