const llmResponse = $json.message?.content ?? $json.choices?.[0]?.message?.content ?? 'Could not parse LLM response.';
const today = new Date().toLocaleDateString('en-GB', { weekday: 'short', day: 'numeric', month: 'short' });

return [{
  json: {
    telegramMessage: `📊 *GitHub Digest — ${today}*\n\n${llmResponse}`
  }
}];
